CREATE TABLE `audit_agent` (`id` INT(11) NOT NULL AUTO_INCREMENT PRIMARY KEY, `org_id` INT(11) DEFAULT 0, INDEX `org_id` (`org_id`), `backend_id` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '', `name` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '', `os_type` ENUM('LINUX','UNKNOWN','WINDOWS') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'unknown', `status` ENUM('OFFLINE','ONLINE','REGISTERED') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'registered', `last_seen` DATETIME, `created_at` DATETIME) ENGINE = innodb CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci
CREATE TABLE `audit` (`id` INT(11) NOT NULL AUTO_INCREMENT PRIMARY KEY, `org_id` INT(11) DEFAULT 0, INDEX `org_id` (`org_id`), `backend_id` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '', `name` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '', `agent_id` INT(11) DEFAULT 0, INDEX `agent_id` (`agent_id`), `status` ENUM('COMPLETED','FAILED','IN_PROGRESS','PENDING') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'pending', `created_at` DATETIME, `started_at` DATETIME, `completed_at` DATETIME) ENGINE = innodb CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci
CREATE TABLE `audit_report` (`id` INT(11) NOT NULL AUTO_INCREMENT PRIMARY KEY, `org_id` INT(11) DEFAULT 0, INDEX `org_id` (`org_id`), `backend_id` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '', `audit_id` INT(11) DEFAULT 0, INDEX `audit_id` (`audit_id`), `created_at` DATETIME, `severity_score` INT(11), `summary` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '') ENGINE = innodb CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci
ALTER TABLE `priv_sync_att_linkset` CHANGE `attribute_qualifier` `attribute_qualifier` VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '\''
